esqlQuery.esql:
FROM logs-nginx.access.otel-*
// Flag each access log entry as a client error (4xx) or not
| EVAL is_4xx = CASE(http.response.status_code >= 400 AND http.response.status_code < 500, 1, 0)
// Aggregate total requests and 4xx count per NGINX host
| STATS total = COUNT(*), errors_4xx = SUM(is_4xx) BY host.name
// Minimum sample size to avoid noisy low-traffic hosts
| WHERE total > 50
// Calculate 4xx error rate as a percentage
| EVAL error_rate_pct = ROUND(TO_DOUBLE(errors_4xx) / TO_DOUBLE(total) * 100.0, 2)
// Alert threshold: 15% is a reasonable starting point for client errors
| WHERE error_rate_pct > 15.0
| SORT error_rate_pct DESC
| LIMIT 10
